 31→interface D1Result<T> {
 32→	success: boolean;
 33→	results: T[];
 34→}
 35→
 36→function queryD1<T>(query: string): T[] {
 37→	const raw = execSync(
 38→		`npx wrangler d1 execute ${D1_DATABASE_NAME} --remote --json --command="${query.replace(/"/g, '\\"')}"`,
 39→		{ encoding: "utf-8", maxBuffer: 50 * 1024 * 1024 },
 40→	);
 41→	const parsed = JSON.parse(raw) as D1Result<T>[];
 42→	return parsed[0]?.results ?? [];
 43→}
