  1→import { join } from "node:path";
  2→import { RPCHandler } from "@orpc/server/fetch";
  3→import { migrate } from "drizzle-orm/postgres-js/migrator";
  4→import { createAuth } from "./auth.js";
  5→import { db } from "./db.js";
  6→import { router } from "./router.js";
  7→
  8→const migrationsFolder = join(
  9→	import.meta.dir,
 10→	"..",
