import { defineConfig } from "drizzle-kit";

export default defineConfig({
	schema: "./src/auth-schema.ts",
	out: "./db/migrations",
	dialect: "postgresql",
});

{
	"name": "@rudel/sql-schema",
	"version": "0.0.0",
	"private": true,
	"type": "module",
	"main": "./src/index.ts",
	"types": "./src/index.ts",
	"exports": {
		".": "./src/index.ts"
	},
	"scripts": {
		"check-types": "tsc --noEmit",
		"drizzle:check": "drizzle-kit check",
		"drizzle:generate": "drizzle-kit generate",
		"migrate": "bun run src/migrate.ts",
		"migrate:ci": "doppler run --project rudel --config ci -- bun run src/migrate.ts",
		"migrate:prd": "doppler run --project rudel --config prd -- bun run src/migrate.ts"
	},
	"dependencies": {
		"drizzle-orm": "0.45.1",
		"postgres": "^3.4.5"
	},
	"devDependencies": {
		"@rudel/typescript-config": "workspace:*",
		"drizzle-kit": "0.31.8",
		"typescript": "5.9.2"
	}
}

